import React, { useRef, useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "./UserDash.css";

const API_BASE = "http://localhost:5000";

const UserDashboard = () => {
  const navigate = useNavigate();

  const videoRef = useRef(null);
  const mediaRecorderRef = useRef(null);
  const recordedChunks = useRef([]);

  const [isRecording, setIsRecording] = useState(false);
  const [recordedVideo, setRecordedVideo] = useState(null);
  const [accidents, setAccidents] = useState([]);
  const [contacts, setContacts] = useState([]);

  /* CHATBOT */
  const [showChatbot, setShowChatbot] = useState(false);
  const [chatMessages, setChatMessages] = useState([
    { sender: "bot", text: "Hi 👋 Are you safe? Do you need help?" }
  ]);
  const [chatInput, setChatInput] = useState("");

  /* ================= PROFILE NAVIGATION ================= */
  const goToProfile = () => {
    navigate("/UserProfile");
  }

  /* ================= FETCH ACCIDENT HISTORY ================= */
  useEffect(() => {
    fetch(`${API_BASE}/admin/accidents`)
      .then(res => res.json())
      .then(data => {
        if (data.success) {
          setAccidents(data.reports);
        }
      })
      .catch(err => console.error("Fetch error:", err));
  }, []);

  /* ================= CAMERA ================= */

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: "environment" },
        audio: true,
      });
      videoRef.current.srcObject = stream;
    } catch {
      alert("Camera access denied");
    }
  };

  const startRecording = () => {
    recordedChunks.current = [];
    const stream = videoRef.current.srcObject;

    if (!stream) {
      alert("Start camera first");
      return;
    }

    const mediaRecorder = new MediaRecorder(stream);
    mediaRecorderRef.current = mediaRecorder;

    mediaRecorder.ondataavailable = (event) => {
      if (event.data.size > 0) recordedChunks.current.push(event.data);
    };

    mediaRecorder.onstop = () => {
      const blob = new Blob(recordedChunks.current, { type: "video/webm" });
      setRecordedVideo(URL.createObjectURL(blob));
    };

    mediaRecorder.start();
    setIsRecording(true);
  };

  const stopRecording = async () => {
    mediaRecorderRef.current.stop();
    videoRef.current.srcObject.getTracks().forEach(t => t.stop());
    setIsRecording(false);

    try {
      await fetch(`${API_BASE}/admin/accidents`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          location: "Bangalore",
          severity: "Medium",
          status: "Reported"
        })
      });

      alert("Accident Report Sent to Server");
    } catch (error) {
      console.error("Accident report error:", error);
    }
  };

  /* ================= AI CHAT ================= */

  const triggerAutoCall = () => {
    if (contacts.length > 0) {
      window.location.href = `tel:${contacts[0].phone}`;
    }
  };

  const sendMessage = async () => {
    if (!chatInput) return;

    const userMessage = chatInput;

    setChatMessages(prev => [
      ...prev,
      { sender: "user", text: userMessage }
    ]);

    setChatInput("");

    try {
      const response = await fetch(`${API_BASE}/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: userMessage })
      });

      if (!response.ok) {
        throw new Error("Server error");
      }

      const text = await response.text();

      let data;
      try {
        data = JSON.parse(text);
      } catch (err) {
        console.error("Invalid JSON from server:", text);
        throw new Error("Invalid JSON format");
      }

      // Trigger emergency if AI says so
      if (data.reply && data.reply.includes("CALL_EMERGENCY_NOW")) {
        triggerAutoCall();
      }

      setChatMessages(prev => [
        ...prev,
        { sender: "bot", text: data.reply }
      ]);

    } catch (error) {
      console.error("Chat Error:", error);
      setChatMessages(prev => [
        ...prev,
        { sender: "bot", text: "Server not responding properly." }
      ]);
    }
  };

  /* ================= CONTACT IMPORT ================= */

  const importContacts = (event) => {
    const file = event.target.files[0];
    if (!file) return;

    const reader = new FileReader();

    reader.onload = (e) => {
      const rows = e.target.result.split("\n");
      const imported = rows
        .map(row => {
          const [name, phone] = row.split(",");
          return { name: name?.trim(), phone: phone?.trim() };
        })
        .filter(c => c.name && c.phone);

      setContacts(imported);
    };

    reader.readAsText(file);
  };

  return (
    <div className="app-container">

      {/* HEADER */}
      <div className="header">
        <h2>Hello 👋</h2>
        <input className="search-bar" placeholder="Search..." />
      </div>

      {/* VIDEO SECTION */}
      <div className="video-card">
        <video ref={videoRef} autoPlay muted></video>

        {!isRecording ? (
          <button className="upload-btn" onClick={startRecording}>
            Start Recording
          </button>
        ) : (
          <button className="stop-btn" onClick={stopRecording}>
            Stop Recording
          </button>
        )}

        <button className="upload-btn" onClick={startCamera}>
          Start Camera
        </button>
      </div>

      {/* RECORDED PREVIEW */}
      {recordedVideo && (
        <div className="video-card">
          <h4>Recorded Preview</h4>
          <video src={recordedVideo} controls />
        </div>
      )}

      {/* ACCIDENT HISTORY */}
      <div className="activity-card">
        <h4>Accident History</h4>
        <ul>
          {accidents.map((acc, index) => (
            <li key={index}>
              {acc.location} - {acc.severity} - {acc.status}
            </li>
          ))}
        </ul>
      </div>

      {/* CONTACT IMPORT */}
      <div className="video-card">
        <h4>Emergency Contacts</h4>
        <input type="file" accept=".csv" onChange={importContacts} />
        <ul className="contact-list">
          {contacts.map((c, i) => (
            <li key={i}>
              {c.name} - {c.phone}
              <a href={`tel:${c.phone}`} className="call-btn">📞</a>
            </li>
          ))}
        </ul>
      </div>

      {/* CHATBOT BUTTON */}
      <button
        className="chatbot-btn"
        onClick={() => setShowChatbot(!showChatbot)}
      >
        💬
      </button>

      {/* CHATBOT */}
      {showChatbot && (
        <div className="chatbot-container">
          <div className="chat-header">
            AI Accident Assistant 🚑
          </div>

          <div className="chat-body">
            {chatMessages.map((msg, i) => (
              <div key={i} className={msg.sender}>
                {msg.text}
              </div>
            ))}
          </div>

          <div className="chat-input">
            <input
              value={chatInput}
              onChange={(e) => setChatInput(e.target.value)}
              placeholder="Type message..."
            />
            <button onClick={sendMessage}>Send</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default UserDashboard;
